module RefModule(
  input wire clk,
  input wire reset,
  output wire [31:0] count
);

  reg [31:0] unused_count_reg;

  always @(posedge clk) begin
    if (reset) begin
      unused_count_reg <= 0;
    end else begin
      unused_count_reg <= unused_count_reg + 1;
    end
  end

  assign count = unused_count_reg;

endmodule
